<script>
export default {
  name: "OptionsGlasses",
  methods: {
  deleteClass() {
    let c = document.getElementById('glasses').children, i;
    for (i = 0; i < c.length; i++) {
      c[i].classList.remove('show');
    }
  },
  showGlasses() {
    if(document.querySelector('#g_glasses').classList.contains('show')) {
      this.deleteClass();
    } else {
      this.deleteClass();
      document.querySelector('#g_glasses').classList.add('show');
    }
  },
  showFancy() {
    if(document.querySelector('#g_fancy').classList.contains('show')) {
